type errorMockFormatter struct{}

func (m *errorMockFormatter) Format(entry *logrus.Entry) ([]byte, error) {
	return nil, ErrMockFormatterError
}

var ErrMockFormatterError = logrus.NewEntry(logrus.New()).WithError(nil).Logger.ReportCaller

